import time
import functools

def timer(func):
    """Decorator that logs execution time of a function."""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)
        end = time.perf_counter()
        print(f"{func.__name__!r} executed in {end - start:.4f} seconds")
        return result
    return wrapper

@timer
def slow_function():
    time.sleep(1)

slow_function()  # Prints: 'slow_function' executed in 1.0012 seconds

Bad Response:
def timer(func):
    def wrapper():
        import time
        start = time.time()
        func()
        print("Time:", time.time() - start)
